#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <unistd.h>
#include <stdbool.h>

#define NUM_CPUS 4
#define MAX_PROCESSES 20
#define LOAD_THRESHOLD 2

// Process structure
typedef struct {
 int pid;
 char name[32];
 int burst_time;
 int remaining_time;
 int preferred_cpu; // Soft affinity
} Process;

// CPU Node structure
typedef struct {
 int cpu_id;
 Process* queue[20];
 int queue_count;
 pthread_mutex_t lock;
 bool busy;
 Process* current_process;
} CPUNode;

// Global scheduler state
CPUNode cpus[NUM_CPUS];
bool load_balancer_running = true;

// Initialize CPU nodes
void init_cpus() {
 for (int i = 0; i < NUM_CPUS; i++) {
 cpus[i].cpu_id = i;
 cpus[i].queue_count = 0;
 cpus[i].busy = false;
 cpus[i].current_process = NULL;
 pthread_mutex_init(&cpus[i].lock, NULL);
 }
}

// Add process to a CPU (enqueue)
void enqueue_process(int cpu_id, Process* p) {
 pthread_mutex_lock(&cpus[cpu_id].lock);
 if (cpus[cpu_id].queue_count < 20) {
 cpus[cpu_id].queue[cpus[cpu_id].queue_count++] = p;
 p->preferred_cpu = cpu_id;
 }
 pthread_mutex_unlock(&cpus[cpu_id].lock);
}

// Remove process from CPU (dequeue)
Process* dequeue_process(int cpu_id) {
 pthread_mutex_lock(&cpus[cpu_id].lock);
 if (cpus[cpu_id].queue_count == 0) {
 pthread_mutex_unlock(&cpus[cpu_id].lock);
 return NULL;
 }

 Process* p = cpus[cpu_id].queue[0];
 // Shift remaining processes
 for (int i = 0; i < cpus[cpu_id].queue_count - 1; i++) {
 cpus[cpu_id].queue[i] = cpus[cpu_id].queue[i + 1];
 }
 cpus[cpu_id].queue_count--;
 pthread_mutex_unlock(&cpus[cpu_id].lock);
 return p;
}

// Get load (queue size + current processing)
int get_cpu_load(int cpu_id) {
 pthread_mutex_lock(&cpus[cpu_id].lock);
 int load = cpus[cpu_id].queue_count + (cpus[cpu_id].busy ? 1 : 0);
 pthread_mutex_unlock(&cpus[cpu_id].lock);
 return load;
}

// Find least loaded CPU for initial placement
int find_least_loaded_cpu() {
 int min_load = get_cpu_load(0);
 int min_cpu = 0;
 for (int i = 1; i < NUM_CPUS; i++) {
 int load = get_cpu_load(i);
 if (load < min_load) {
 min_load = load;
 min_cpu = i;
 }
 }
 return min_cpu;
}

// Get process with affinity (soft affinity)
Process* get_process_with_affinity(int cpu_id) {
 pthread_mutex_lock(&cpus[cpu_id].lock);

 if (cpus[cpu_id].queue_count == 0) {
 pthread_mutex_unlock(&cpus[cpu_id].lock);
 return NULL;
 }

 // Search for process with affinity to this CPU
 for (int i = 0; i < cpus[cpu_id].queue_count; i++) {
 if (cpus[cpu_id].queue[i]->preferred_cpu == cpu_id) {
 Process* p = cpus[cpu_id].queue[i];
 // Remove from queue
 for (int j = i; j < cpus[cpu_id].queue_count - 1; j++) {
 cpus[cpu_id].queue[j] = cpus[cpu_id].queue[j + 1];
 }
 cpus[cpu_id].queue_count--;
 pthread_mutex_unlock(&cpus[cpu_id].lock);
 return p;
 }
 }

 // No affinity match - take first in queue
 Process* p = cpus[cpu_id].queue[0];
 for (int i = 0; i < cpus[cpu_id].queue_count - 1; i++) {
 cpus[cpu_id].queue[i] = cpus[cpu_id].queue[i + 1];
 }
 cpus[cpu_id].queue_count--;
 pthread_mutex_unlock(&cpus[cpu_id].lock);
 return p;
}

// CPU scheduler thread function
void* cpu_scheduler(void* arg) {
 int cpu_id = *(int*)arg;

 while (1) {
 // Try to get process with affinity
 Process* p = get_process_with_affinity(cpu_id);

 if (p != NULL) {
 cpus[cpu_id].busy = true;
 cpus[cpu_id].current_process = p;

 printf("[CPU %d] Executing %s (remaining: %ds)\n", 
 cpu_id, p->name, p->remaining_time);

 // Simulate execution (sleep for burst)
 sleep(1);
 p->remaining_time--;

 if (p->remaining_time > 0) {
 // Re-queue the process
 enqueue_process(cpu_id, p);
 } else {
 printf("[CPU %d] Process %s COMPLETED\n", cpu_id, p->name);
 }

 cpus[cpu_id].current_process = NULL;
 cpus[cpu_id].busy = false;
 } else {
 // Idle - try pull migration
 usleep(100000); // Sleep 100ms
 }
 }
 return NULL;
}

// Load balancer thread function (push migration)
void* load_balancer(void* arg) {
 while (load_balancer_running) {
 sleep(2); // Check every 2 seconds

 // Find max and min loaded CPUs
 int max_cpu = 0, min_cpu = 0;
 int max_load = get_cpu_load(0);
 int min_load = get_cpu_load(0);

 for (int i = 1; i < NUM_CPUS; i++) {
 int load = get_cpu_load(i);
 if (load > max_load) {
 max_load = load;
 max_cpu = i;
 }
 if (load < min_load) {
 min_load = load;
 min_cpu = i;
 }
 }

 // Perform load balancing if threshold exceeded
 if (max_load - min_load >= LOAD_THRESHOLD) {
 Process* p = dequeue_process(max_cpu);
 if (p != NULL) {
 p->preferred_cpu = min_cpu; // Update affinity
 enqueue_process(min_cpu, p);
 printf("[Load Balancer] Migrated %s from CPU %d to CPU %d\n",
 p->name, max_cpu, min_cpu);
 }
 }
 }
 return NULL;
}

int main() {
 printf("=== SMP Multiprocessor Scheduling Simulation ===\n\n");

 // Initialize CPU nodes
 init_cpus();

 // Create sample processes
 Process processes[] = {
 {1, "Chrome", 8, 8, -1},
 {2, "VSCode", 5, 5, -1},
 {3, "Compiler", 10, 10, -1},
 {4, "MediaPlayer", 3, 3, -1},
 {5, "Database", 7, 7, -1},
 {6, "WebServer", 6, 6, -1},
 {7, "BackupSvc", 4, 4, -1},
 {8, "Logger", 5, 5, -1},
 };

 int num_processes = sizeof(processes) / sizeof(processes[0]);

 // Add processes to least loaded CPUs
 for (int i = 0; i < num_processes; i++) {
 int target_cpu = find_least_loaded_cpu();
 enqueue_process(target_cpu, &processes[i]);
 printf("[Scheduler] Added %s to CPU %d\n", 
 processes[i].name, target_cpu);
 }

 printf("\n--- Starting CPU Schedulers ---\n\n");

 // Create CPU scheduler threads
 pthread_t cpu_threads[NUM_CPUS];
 int cpu_ids[NUM_CPUS];

 for (int i = 0; i < NUM_CPUS; i++) {
 cpu_ids[i] = i;
 pthread_create(&cpu_threads[i], NULL, cpu_scheduler, &cpu_ids[i]);
 }

 // Create load balancer thread
 pthread_t lb_thread;
 pthread_create(&lb_thread, NULL, load_balancer, NULL);

 // Run for 15 seconds
 sleep(15);

 // Stop load balancer
 load_balancer_running = false;

 printf("\n=== Simulation Complete ===\n");

 return 0;
}
